css:
/*作者：lazyalie*/
/*没有任何技术含量全靠拼拼，感谢各位老师，全部都标源啦*/


/* 🍓感谢nini老师分享的隐藏输入框右下角的缩放手柄（小黑点） */
#send_textarea {
    resize: none !important;
}

/*最后一条消息和输入框间距*/
#chat .mes:last-of-type {

    margin-bottom: 150px !important; 

}


/*🍅感谢墨千尾老师分享的正则留空*/
/* 正则右侧滑动区，想左侧留空的把right改成left，数字控制留空区域大小 */
#saved_regex_scripts {
  padding-right: 50px; /* 或 margin-right: 15px; */
}
#saved_scoped_scripts {
padding-right: 50px; /* 或 margin-right: 15px; */
}


/* 收藏角色静态边缘泛光效果 */
.character_select.is_fav .avatar {
    outline: none !important;
    box-shadow: 
        0 0 8px rgba(255, 255, 255, 0.8),
        0 0 16px rgba(255, 255, 255, 0.6),
        0 0 24px rgba(255, 255, 255, 0.4);
}

/* 名字静态发光效果 */
.character_select.is_fav .ch_name {
    color: rgba(255, 255, 255, 0.9) !important;
    text-shadow: 
        0 0 8px rgba(255, 255, 255, 0.8),
        0 0 12px rgba(255, 255, 255, 0.6),
        0 0 16px rgba(255, 255, 255, 0.4);
}

/*🍎感谢墨千尾老师分享的拼好码模板*/

/* ===== 顶栏美化 ===== */
/* 顶栏毛玻璃效果 */
#top-settings-holder {
    background: rgba(255, 255, 255, 0.1) !important;
    backdrop-filter: blur(10px) saturate(180%);
    -webkit-backdrop-filter: blur(10px) saturate(180%);
    border-radius: 12px;
    box-shadow: none;
    border: 1px solid rgba(255, 255, 255, 0.1);
}

/* 确保父容器圆角 */
#top-bar {
    border-radius: 12px !important;
    background-color: transparent !important;
    box-shadow: none !important;
    border: none !important;
}

/* 顶栏图标替换 - 不同图片 */
#top-settings-holder .drawer-icon::before {
    content: '' !important;
    visibility: hidden;
}

#top-settings-holder .drawer {
    flex: 1;
}

#top-settings-holder .drawer-icon {
    display: block;
    margin: 0 auto;
    background-size: contain;
    background-position: center;
    background-repeat: no-repeat;
    transition: all 0.3s ease-in-out;
    width: 24px;
    height: 24px;
    opacity: 1 !important;
}

/* 悬停效果 */
.drawer-icon.fa-fw:hover {
    transform: scale(1.2);
    transition: transform 0.2s ease-in-out;
}

/* 分别设置每个图标的图片 */
/* 图标1: AI 响应配置/预设页面 */
#ai-config-button .drawer-icon {
   background-image: url('https://files.catbox.moe/unl16j.PNG');
}

/* 图标2: API 连接 */
#sys-settings-button .drawer-icon {
   background-image: url('https://files.catbox.moe/olnbxn.PNG');
}

/* 图标3: AI回复格式化 */
#advanced-formatting-button .drawer-icon {
   background-image: url('https://files.catbox.moe/bvg00w.PNG');
}

/* 图标4: 世界信息 */
#WI-SP-button .drawer-icon {
   background-image: url('https://files.catbox.moe/z2elha.PNG');
}

/* 图标5: 用户设置 */
#user-settings-button .drawer-icon {
   background-image: url('https://files.catbox.moe/mktshr.PNG');
}

/* 图标6: 背景图片 */
#logo_block .drawer-icon {
   background-image: url('https://files.catbox.moe/uyr0ch.PNG');
}

/* 图标7: 扩展 */
#extensions-settings-button .drawer-icon {
   background-image: url('https://files.catbox.moe/afbbwa.PNG');
}

/* 图标8: 记忆表格 */
#table_database_settings_drawer .drawer-icon {
   background-image: url('https://files.catbox.moe/afbbwa.PNG');
}

/* 图标9: 用户角色管理 */
#persona-management-button .drawer-icon {
   background-image: url('https://files.catbox.moe/ydtjv5.PNG');
}

/* 图标10: 角色卡 */
#rightNavHolder .drawer-icon {
   background-image: url('https://files.catbox.moe/ifb931.PNG');
}

/* 顶栏图标点击后变为统一图片 */
#top-settings-holder .drawer .drawer-icon.openIcon {
    background-image: url('https://files.catbox.moe/98ut30.PNG') !important;
    transform: scale(1.1);
    transition: all 0.3s ease-in-out;
}
/* 💚======= 顶栏毛玻璃调节 ======= 💚*/
/* 顶栏自定义毛玻璃效果 - 独立控制模糊程度 */
#top-settings-holder {
    --topbar-blur-strength: 5px; /* 越大越模糊 */
    --topbar-saturation: 250%; /* 越大越饱和 */

    backdrop-filter: 
        blur(var(--topbar-blur-strength)) 
        saturate(var(--topbar-saturation)) !important;
    -webkit-backdrop-filter: 
        blur(var(--topbar-blur-strength)) 
        saturate(var(--topbar-saturation)) !important;
}

/* 顶栏悬停时增强模糊效果 */
#top-settings-holder:hover {
    --topbar-blur-strength: 5px !important; /* 悬停时稍微增强模糊 */
    --topbar-saturation: 250% !important; /* 悬停时色彩更鲜艳 */
}
/* 💚============================= 💚*/

/* ===== 底栏美化 ===== */
/* 底栏图标替换为同一张图片 */
#send_form [class*="fa-"]::before {
    content: '' !important;
    display: inline-block;
    width: 20px;
    height: 20px;
    background-image: url('https://files.catbox.moe/98ut30.PNG');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    vertical-align: middle;
    transition: all 0.3s ease-in-out;
}

/* 停止图标单独设置 */
#mes_stop i::before {
    background-image: url('https://files.catbox.moe/98ut30.PNG') !important;
}

/* 底栏图标悬停效果 */
#send_form [class*="fa-"]:hover::before {
    transform: scale(1.2);
    transition: transform 0.2s ease-in-out;
}
/* 设置气泡整体布局 */
.mes {
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
}
/* ===== 用户与角色气泡美化 ===== */
/* 只给非最后一条消息设置底部间距  */
.mes:not(:last-child) {
    margin-bottom: 30px !important; /* 用户与AI气泡之间的垂直间距，可修改数值 */
}

/* 头像容器定位 */
.mes .mesAvatarWrapper {
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    position: relative !important;
    z-index: 10 !important;
}

/*  修复 1: 稳定头像装饰的锚点 */
/* 头像样式 */
.mes .avatar {
    margin-bottom: 8px !important; /* 头像与下方信息的距离，可修改数值 */
    z-index: 2 !important;
    position: relative !important; 
}

/*  修复 1: 确保装饰图片以头像中心稳定对齐 */
/* 头像底部装饰图片 */
.mes .avatar::after { 
    content: '' !important;
    position: absolute !important;
    top: 50% !important;
    left: 50% !important;
    transform: translate(-50%, -48%) !important; /*  图片上下移动位置，已微调 */
    width: 550px !important; /* 图片宽度，可修改数值 */
    height: 550px !important; /* 图片高度，可修改数值 */
    background-image: url('https://files.catbox.moe/543xen.PNG') !important;
    background-size: contain !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
    z-index: -1 !important; /* 确保图片在头像下方 */
    pointer-events: none !important;
}


/* 移除用户气泡头像装饰图片 */
.mes[is_user="true"] .avatar::after {
    display: none !important;
}

/* 用户头像泛白光效果（无黑边） */
.mes[is_user="true"] .avatar img {
    box-shadow: 
        0 0 10px rgba(255, 255, 255, 0.8),
        0 0 20px rgba(255, 255, 255, 0.6),
        0 0 30px rgba(255, 255, 255, 0.4) !important;
    filter: brightness(1.1) !important;
    border: none !important;
    outline: none !important;
}

/* 头像图片 */
.mes .avatar img {
    border-radius: 50% !important;
    z-index: 2 !important;
    position: relative !important;
}

/*  修复 2: 确保气泡顶部对齐的关键间距 */
/* 信息容器（名字、时间、楼层等） */
.mesAvatarWrapper > .flex-container {
    display: flex !important;
    flex-direction: column !important;
    align-items: center !important;
    gap: 2px !important; /* 信息项之间的间距，可修改数值 */
    margin-top: 5px !important;
    margin-bottom: 15px !important; 
    z-index: 2 !important;
    position: relative !important;
}

/* 信息文字样式 */
.mesAvatarWrapper .mes_timer,
.mesAvatarWrapper .mesIDDisplay,
.mesAvatarWrapper .tokenCounterDisplay,
.mesAvatarWrapper .name_text {
    font-size: 12px !important;
    text-align: center !important;
    color: var(--main-text-color) !important;
}

/* 气泡主体样式 */
.mes .mes_block {
    width: calc(100% - 60px) !important; /* 气泡左右边距，可修改60px数值 */
    max-width: none !important;
    border-radius: 20px !important; /* 气泡圆角大小，可修改数值 */
    padding: 15px !important;
    position: relative !important;
    margin-top: 0 !important; /* 确保气泡紧贴 flex-container 的底部 */
}

/* 💚======= 气泡毛玻璃调节 ======= 💚*/
.mes .mes_block {
    /* 独立控制毛玻璃，% 的数值越大越饱和，px数值越大越模糊 */
    backdrop-filter: blur(10px) saturate(220%) !important; 
    -webkit-backdrop-filter: blur(10px) saturate(220%) !important;
}
/* 💚===========================💚 */


/* 用户气泡颜色 */
/* 注意：这里只保留颜色，模糊效果由独立调节块控制 */
.mes[is_user="true"] .mes_block {
    background-color: var(--user-mes-blur-tint-color) !important;
    /* backdrop-filter 已移除 */
    /* -webkit-backdrop-filter 已移除 */
}

/* AI角色气泡颜色  */
/* 注意：这里只保留颜色，模糊效果由独立调节块控制 */
.mes[is_user="false"] .mes_block {
    background-color: var(--bot-mes-blur-tint-color) !important;
    /* backdrop-filter 已移除 */
    /* -webkit-backdrop-filter 已移除 */
}

/* 气泡辉光效果  */
.mes .mes_block {
    box-shadow: 
        0 0 15px 5px var(--border-color) !important; /* 辉光效果范围，已修改扩散程度为 5px */
}

/* 确保思维链和正文正常显示 */
.mes .mes_text {
    width: 100% !important;
    padding: 0 !important;
}

/* 思维链样式调整 */
.mes .mes_reasoning {
    margin-top: 10px !important;
    width: 100% !important;
}

/* 响应式调整 */
@media (max-width: 768px) {
    .mes .mes_block {
        width: calc(100% - 0px) !important; /* 移动端气泡左右边距，已修改为全宽 */
    }
}

/*🍋感谢墨千尾老师的发光文本美化*/
q {
    color: rgba(255, 255, 255, 1); /* 白色文字 */
    font-style: normal; /* 取消默认斜体 */
    font-size: 1.2em; /* 放大一点点 - 调整为原大小的110% */
    /* 白色发光效果 - 多层阴影创建柔和光晕 */
    text-shadow: 
        0 0 5px rgba(255, 255, 255, 0.8),
        0 0 10px rgba(255, 255, 255, 0.6),
        0 0 15px rgba(255, 255, 255, 0.4);
}
/*斜体下划线*/
em {
    text-decoration: underline;
    text-decoration-style: dashed;
    text-decoration-color: rgba(255, 255, 255, 0.8);
    text-shadow: 0 0 3px rgba(255, 255, 255, 0.5);
    text-decoration-thickness: 1px;
    text-underline-offset: 2px;
}

/*🍉感谢nakari老师分享的最后一条消息与下方区域距离保持一致代码*/
/* 通用CSS */
.mes .mes_timer:empty,
.mes .mesIDDisplay:empty,
.mes .tokenCounterDisplay:empty {
    display: none;
}

.last_mes .mesAvatarWrapper {
    padding-bottom: 10px; /* 最后一条消息头像区域与下方间距，保持与前面一致 */
}

/* === 思维链美化 === */
.mes_reasoning_summary {
    list-style: none;
    cursor: pointer;
    display: flex !important;
    align-items: center;
    justify-content: center; /* 居中 */
}

.mes_reasoning_header {
    background: rgba(255, 255, 255, 0); /* 完全透明背景 */
    backdrop-filter: blur(10px) saturate(180%);
    -webkit-backdrop-filter: blur(10px) saturate(180%);
    border-radius: 12px;
    padding: 10px 20px;
    border: none !important;
    transition: transform 0.3s ease; /* 只保留transform过渡，移除background过渡 */
    text-align: center;
    margin: auto; /* 居中 */
}

/* 移除点击后的背景色变化 */
.mes_reasoning_summary:hover .mes_reasoning_header {
    transform: scale(1.05);
    /* 移除 background 变化，保持透明 */
}

.mes_reasoning_header_title {
    font-size: 0 !important;
}

.mes_reasoning_header_title::before {
    content: "⋆⁺₊⋆ ☾ ⋆⁺₊⋆";
    font-size: 14px;
    color: #CDCDCD;
    font-weight: 600;
    letter-spacing: 1px;
}

.mes_reasoning_arrow {
    font-size: 0 !important;
}

.mes_reasoning {
    margin: 8px auto 0;
    padding: 16px;
    background: rgba(0, 0, 0, 0.2);
    backdrop-filter: blur(8px);
    -webkit-backdrop-filter: blur(8px);
    border-radius: 8px;
    color: #CDCDCD;
    font-family: monospace;
    font-size: 13px;
    line-height: 1.5;
    text-align: left;
    max-width: 90%;
}



/*🍏感谢royoyo老师分享的二改NA师的悬浮底栏*/
/* 美化输入框容器 (#send_form) */
#send_form {
    /* 继承并跟随UI原本的主题色 */
    background-color: var(--底栏背景色, rgba(255, 255, 255, 0.1)); 
    border: 2px solid var(--边框颜色, rgba(255, 255, 255, 0.2));

    width: 98%;
    /* 强制使用弹性布局，确保内部元素对齐 */
    display: flex !important;
    align-items: center !important;

    /* 统一设置圆角 */
    border-radius: 16px !important; 
    /* 调整内边距，并强制生效 */
    padding: 8px 15px !important; 
    /* 背景模糊效果 - 毛玻璃效果 */
    backdrop-filter: blur(10px) saturate(180%);
    -webkit-backdrop-filter: blur(10px) saturate(180%);
    /* 阴影效果 */
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
    /* 动画效果，所有属性都平滑过渡 */
    transition: all 0.3s ease; 

    /* 未激活时，设置半透明效果 */
    opacity: 0.3;
}

/* 鼠标悬停效果 */
#send_form:hover {
    /* 向上平移 */
    transform: translateY(-5px);
    /* 阴影效果 */
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.4);
    /* 边框 */
    border: 1px solid var(--悬停边框颜色, rgba(255, 255, 255, 0.4));
    /* 悬停时恢复不透明 */
    opacity: 1;
    /* 增强毛玻璃效果 */
    backdrop-filter: blur(12px) saturate(200%);
    -webkit-backdrop-filter: blur(12px) saturate(200%);
}

/* 激活后（输入框获得焦点时）的效果 */
#send_form:focus-within {
    /* 完全不透明 */
    opacity: 1; 
    /* 调整阴影以增强激活状态的视觉效果 */
    box-shadow: 0 6px 25px rgba(0, 0, 0, 0.4); 
    /* 轻微向上平移，与悬停效果类似，但可以区分开 */
    transform: translateY(-2px); 
    /* 边框高亮 */
    border: 2px solid var(--悬停边框颜色, rgba(255, 255, 255, 0.6));
    /* 激活时毛玻璃效果 */
    backdrop-filter: blur(15px) saturate(220%);
    -webkit-backdrop-filter: blur(15px) saturate(220%);
}

/* 美化文本输入区域 (#send_textarea) */
#send_textarea {
    /* 允许文本框填充剩余空间，并随内容自动调整高度，并强制生效 */
    flex-grow: 1 !important;
    /* 最小高度，使其与图标保持一致，并强制生效 */
    min-height: 24px !important; 
    /* 移除多余的行高，防止文字将输入框撑高 */
    line-height: 1.5; 

    /* 顶部边框完整显示 */
    clip-path: none; 
    /* 隐藏容器视觉效果，确保外层圆角能显示 */
    background-color: transparent;
    border-color: transparent;
    /* 内部文本框也需要圆角，否则会遮挡底部圆角 */
    border-radius: 16px !important;
}

/* 确保输入框固定在底部 */
#form_sheld {
    position: sticky;
    bottom: 100px;
    transition: transform 0.3s ease;
}

/* 鼠标悬浮在整个底部区域时，向上平移 */
#form_sheld:hover {
    transform: translateY(-5px);
}

/* 布局调整，让内容占满屏幕 */
#sheld, 
#chat {
    height: calc(100dvh + var(--bottomFormBlockSize));
    max-height: calc(100dvh + var(--bottomFormBlockSize));
}

/* 最后一条消息与底部间距 */
.last_mes {
    margin-bottom: 150px !important;
}

/* QR-bar 样式 - 确保其定位优先级最高 */
#qr--bar {
    position: absolute !important;
    bottom: calc(100% + 5px) !important; 
    right: 0 !important;

    /* 初始状态：完全隐藏 */
    opacity: 0;
    height: 0;
    overflow: hidden;

    /* 平滑过渡 */
    transition: opacity 0.5s ease, height 0.5s ease;
}

/* 悬停时显示效果 - 强制生效 */
#send_form:hover #qr--bar {
    opacity: 1 !important;
    height: 40px !important;
}

/* 💚===== 输入框独立毛玻璃调节 ===== 💚*/
/* 自定义毛玻璃效果 - 独立控制模糊程度 */
#send_form {
    /* 基础模糊程度设置 */
    --custom-blur-strength: 5px; /* 越大越模糊*/
    --custom-saturation: 500%; /* 自定义饱和度，越大饱和度越高 */

    backdrop-filter: 
        blur(var(--custom-blur-strength)) 
        saturate(var(--custom-saturation)) !important;
    -webkit-backdrop-filter: 
        blur(var(--custom-blur-strength)) 
        saturate(var(--custom-saturation)) !important;
}

/* 鼠标悬停时增强模糊效果 */
#send_form:hover {
    --custom-blur-strength: 12px !important; /* 悬停时稍微增强模糊 */
    --custom-saturation: 500% !important; /* 悬停时色彩更鲜艳 */
}

/* 激活时最强模糊效果 */
#send_form:focus-within {
    --custom-blur-strength: 5px !important; /* 聚焦时最强模糊效果 */
    --custom-saturation: 500% !important; /* 聚焦时最高饱和度 */
}
/* 💚=========================== 💚*/


/* 底栏呼吸灯效果 */
#send_form {
    position: relative;
    transition: all 0.5s ease-in-out;
}

#send_form:hover {
    box-shadow: 
        0 0 5px rgba(255, 255, 255, 0.6),
        0 0 10px rgba(255, 255, 255, 0.4),
        0 0 15px rgba(255, 255, 255, 0.2);
    animation: breathe 5s ease-in-out infinite;
}

/* 呼吸灯动画 */
@keyframes breathe {
    0% {
        box-shadow: 
            0 0 5px rgba(255, 255, 255, 0.6),
            0 0 10px rgba(255, 255, 255, 0.4),
            0 0 15px rgba(255, 255, 255, 0.2);
    }
    50% {
        box-shadow: 
            0 0 10px rgba(255, 255, 255, 0.8),
            0 0 20px rgba(255, 255, 255, 0.6),
            0 0 30px rgba(255, 255, 255, 0.4);
    }
    100% {
        box-shadow: 
            0 0 5px rgba(255, 255, 255, 0.6),
            0 0 10px rgba(255, 255, 255, 0.4),
            0 0 15px rgba(255, 255, 255, 0.2);
    }
}
/* 🍐感谢墨千尾老师分享的通用输入框提示词自定义  */
#nonQRFormItems {
    position: relative;
}

#send_textarea::placeholder {
    color: transparent !important;
    text-shadow: none !important; /* 移除可能存在的文字阴影 */
}

#nonQRFormItems:has(#send_textarea:placeholder-shown)::before {
    content: "人间何所以，观风与月舒 "; 
    color: #cdcdcd; /*  自定义颜色 */
    left: 120px; /*  自定义位置 */

    position: absolute; 
    top: 50%; /* 垂直居中 */
    transform: translateY(-50%); /* 精确垂直居中 */

    font-style: normal; /* 字体样式 */
    font-size: 0.5em;  /* 字体大小：相对于输入框的字体大小 */

    pointer-events: none;
    z-index: 10; 

    /* 为了防止文字过长而换行 */
    white-space: nowrap; 
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: calc(100% - 30px); /* 限制最大宽度，防止溢出输入框 */
}


